   298→// Update job
   299→router.put('/jobs/:id', authMiddleware, requireRecruiter, async (req, res) => {
   300→  try {
   301→    const { title, description, requirements, location, salary_range, job_type, status, screening_questions } = req.body;
   302→
   303→    // Verify ownership (company_id or user_id)
   304→    const existing = await pool.query(
   305→      'SELECT id FROM jobs WHERE id = $1 AND (company_id = $2 OR user_id = $3)',
   306→      [req.params.id, req.user.company_id, req.user.id]
   307→    );
   308→
   309→    if (existing.rows.length === 0) {
   310→      return res.status(404).json({ error: 'Job not found' });
   311→    }
   312→
   313→    const result = await pool.query(
   314→      `UPDATE jobs SET
   315→        title = COALESCE($1, title),
   316→        description = COALESCE($2, description),
   317→        requirements = COALESCE($3, requirements),
   318→        location = COALESCE($4, location),
   319→        salary_range = COALESCE($5, salary_range),
   320→        job_type = COALESCE($6, job_type),
   321→        status = COALESCE($7, status),
   322→        screening_questions = COALESCE($8, screening_questions),
   323→        updated_at = NOW()
   324→       WHERE id = $9
   325→       RETURNING *`,
   326→      [title, description, requirements, location, salary_range, job_type, status, screening_questions || null, req.params.id]
