   336→// Get ALL applications for the company
   337→router.get('/applications', authMiddleware, requireRecruiter, async (req, res) => {
   338→  try {
   339→    const { status, job_id, limit = 100, offset = 0 } = req.query;
   340→
   341→    let query = `
   342→      SELECT ja.*,
   343→             u.name as candidate_name, u.email as candidate_email,
   344→             j.title as job_title, j.id as job_id,
   345→             j.screening_questions,
   346→             os.total_score as current_omniscore, os.score_tier,
   347→             (SELECT COUNT(*) FROM skill_assessments sa2 JOIN candidate_skills cs2 ON sa2.skill_id = cs2.id WHERE cs2.user_id = ja.candidate_id AND sa2.passed = true) as verified_skills_count,
   348→             (SELECT MAX(i2.overall_score) FROM interviews i2 WHERE i2.user_id = ja.candidate_id AND i2.status = 'completed') as best_interview_score,
   349→             (SELECT COUNT(*) FROM interviews i3 WHERE i3.user_id = ja.candidate_id AND i3.status = 'completed') as completed_interviews
   350→      FROM job_applications ja
   351→      JOIN users u ON ja.candidate_id = u.id
   352→      JOIN jobs j ON ja.job_id = j.id
   353→      LEFT JOIN omni_scores os ON u.id = os.user_id
   354→      WHERE ja.company_id = $1
   355→    `;
   356→    const params = [req.user.company_id];
   357→
   358→    if (status) {
   359→      query += ` AND ja.status = $${params.length + 1}`;
   360→      params.push(status);
   361→    }
   362→
   363→    if (job_id) {
   364→      query += ` AND ja.job_id = $${params.length + 1}`;
   365→      params.push(job_id);
   366→    }
   367→
   368→    query += ` ORDER BY ja.applied_at DESC LIMIT $${params.length + 1} OFFSET $${params.length + 2}`;
   369→    params.push(limit, offset);
