   962→// Batch update application status (for bulk actions)
   963→router.put('/applications/batch-status', authMiddleware, requireRecruiter, async (req, res) => {
   964→  try {
   965→    const { application_ids, status } = req.body;
   966→
   967→    if (!application_ids || !Array.isArray(application_ids) || application_ids.length === 0) {
   968→      return res.status(400).json({ error: 'application_ids array required' });
   969→    }
   970→
   971→    if (!status || !PIPELINE_STAGES.includes(status)) {
   972→      return res.status(400).json({ error: `Invalid status. Must be one of: ${PIPELINE_STAGES.join(', ')}` });
   973→    }
   974→
   975→    if (application_ids.length > 50) {
   976→      return res.status(400).json({ error: 'Max 50 applications per batch' });
   977→    }
   978→
   979→    // Verify all applications belong to the company
   980→    const placeholders = application_ids.map((_, i) => `$${i + 2}`).join(',');
   981→    const verification = await pool.query(
   982→      `SELECT id FROM job_applications WHERE company_id = $1 AND id IN (${placeholders})`,
   983→      [req.user.company_id, ...application_ids]
   984→    );
   985→
   986→    const validIds = verification.rows.map(r => r.id);
   987→    if (validIds.length === 0) {
   988→      return res.status(404).json({ error: 'No valid applications found' });
   989→    }
   990→
   991→    // Update all valid applications
   992→    const updatePlaceholders = validIds.map((_, i) => `$${i + 2}`).join(',');
   993→    const result = await pool.query(
   994→      `UPDATE job_applications SET status = $1, updated_at = NOW() WHERE id IN (${updatePlaceholders}) RETURNING *`,
   995→      [status, ...validIds]
   996→    );
