   998→    // Audit log batch action
   999→    await AuditLogger.log({
  1000→      actionType: 'batch_status_change',
  1001→      userId: req.user.id,
  1002→      targetType: 'job_applications',
  1003→      targetId: null,
  1004→      metadata: {
  1005→        application_ids: validIds,
  1006→        new_status: status,
  1007→        count: validIds.length
  1008→      },
  1009→      req
  1010→    });
  1011→
  1012→    res.json({
  1013→      success: true,
  1014→      updated: result.rows.length,
  1015→      applications: result.rows
  1016→    });
  1017→  } catch (err) {
