  1023→// Get applications grouped by pipeline stage (for kanban view)
  1024→router.get('/pipeline/:jobId', authMiddleware, requireRecruiter, async (req, res) => {
  1025→  try {
  1026→    const jobId = req.params.jobId;
  1027→
  1028→    // Verify job belongs to company
  1029→    const job = await pool.query(
  1030→      'SELECT id, title, status FROM jobs WHERE id = $1 AND (company_id = $2 OR user_id = $3)',
  1031→      [jobId, req.user.company_id, req.user.id]
  1032→    );
  1033→
  1034→    if (job.rows.length === 0) {
  1035→      return res.status(404).json({ error: 'Job not found' });
  1036→    }
  1037→
  1038→    // Get all applications for this job with candidate details
  1039→    const applications = await pool.query(`
  1040→      SELECT ja.*,
  1041→             u.name as candidate_name, u.email as candidate_email,
  1042→             os.total_score as current_omniscore, os.score_tier,
  1043→             (SELECT COUNT(*) FROM skill_assessments sa2 JOIN candidate_skills cs2 ON sa2.skill_id = cs2.id WHERE cs2.user_id = ja.candidate_id AND sa2.passed = true) as verified_skills_count,
  1044→             (SELECT MAX(i2.overall_score) FROM interviews i2 WHERE i2.user_id = ja.candidate_id AND i2.status = 'completed') as best_interview_score
  1045→      FROM job_applications ja
  1046→      JOIN users u ON ja.candidate_id = u.id
  1047→      LEFT JOIN omni_scores os ON u.id = os.user_id
  1048→      WHERE ja.job_id = $1
  1049→      ORDER BY ja.match_score DESC NULLS LAST, ja.applied_at ASC
  1050→    `, [jobId]);
  1051→
  1052→    // Group by pipeline stage
  1053→    const pipeline = {};
  1054→    for (const stage of PIPELINE_STAGES) {
  1055→      pipeline[stage] = [];
  1056→    }
  1057→
  1058→    for (const app of applications.rows) {
  1059→      const stage = PIPELINE_STAGES.includes(app.status) ? app.status : 'applied';
  1060→      pipeline[stage].push(app);
  1061→    }
  1062→
  1063→    // Get stage counts
  1064→    const stageCounts = {};
  1065→    for (const stage of PIPELINE_STAGES) {
  1066→      stageCounts[stage] = pipeline[stage].length;
  1067→    }
  1068→
  1069→    res.json({
  1070→      success: true,
  1071→      job: job.rows[0],
  1072→      pipeline,
  1073→      stage_counts: stageCounts,
  1074→      total: applications.rows.length,
  1075→      stages: PIPELINE_STAGES
  1076→    });
  1077→  } catch (err) {
