  1790→// Trigger pipeline auto-advance check for a job (event-driven: call after application status change)
  1791→router.post('/pipeline/auto-check/:jobId', authMiddleware, requireRecruiter, async (req, res) => {
  1792→  try {
  1793→    const jobId = req.params.jobId;
  1794→
  1795→    // Get automation rules
  1796→    const rules = await pool.query(`
  1797→      SELECT * FROM pipeline_automation_rules
  1798→      WHERE job_id = $1 AND recruiter_id = $2 AND (auto_advance = true OR auto_reject = true)
  1799→    `, [jobId, req.user.id]);
  1800→
  1801→    if (rules.rows.length === 0) {
  1802→      return res.json({ success: true, actions: [], message: 'No automation rules configured' });
  1803→    }
  1804→
  1805→    const actions = [];
  1806→
  1807→    // Get all active applications for this job
  1808→    const apps = await pool.query(`
  1809→      SELECT ja.id, ja.candidate_id, ja.status, ja.match_score,
  1810→             os.total_score as omniscore
  1811→      FROM job_applications ja
  1812→      LEFT JOIN omni_scores os ON os.user_id = ja.candidate_id
  1813→      WHERE ja.job_id = $1 AND ja.status NOT IN ('withdrawn', 'rejected', 'hired')
  1814→    `, [jobId]);
  1815→
  1816→    for (const app of apps.rows) {
  1817→      for (const rule of rules.rows) {
  1818→        if (app.status !== rule.from_stage) continue;
  1819→
  1820→        const omniscore = app.omniscore || 300;
  1821→        const matchScore = app.match_score || 0;
  1822→
  1823→        // Auto-advance check
  1824→        if (rule.auto_advance && omniscore >= rule.omniscore_threshold && matchScore >= rule.match_score_threshold) {
  1825→          await pool.query(
  1826→            `UPDATE job_applications SET status = $1, updated_at = NOW() WHERE id = $2`,
  1827→            [rule.to_stage, app.id]
  1828→          );
  1829→          actions.push({ type: 'advanced', application_id: app.id, candidate_id: app.candidate_id, from: rule.from_stage, to: rule.to_stage, reason: `OmniScore ${omniscore} >= ${rule.omniscore_threshold} and match ${matchScore} >= ${rule.match_score_threshold}` });
  1830→        }
  1831→
  1832→        // Auto-reject check
  1833→        if (rule.auto_reject && omniscore < rule.auto_reject_threshold) {
  1834→          await pool.query(
  1835→            `UPDATE job_applications SET status = 'rejected', updated_at = NOW() WHERE id = $1`,
  1836→            [app.id]
  1837→          );
  1838→          actions.push({ type: 'rejected', application_id: app.id, candidate_id: app.candidate_id, from: rule.from_stage, reason: `OmniScore ${omniscore} < ${rule.auto_reject_threshold}` });
  1839→        }
  1840→      }
  1841→    }
  1842→
  1843→    res.json({ success: true, actions, total_checked: apps.rows.length, rules_applied: rules.rows.length });
  1844→  } catch (err) {
  1845→    console.error('Pipeline auto-check error:', err);
  1846→    res.status(500).json({ error: 'Failed to run pipeline automation' });
  1847→  }
  1848→});
